<script lang="ts">
	import { t } from "$lib/i18n/index.svelte";
	import ScrollableContainer from "$components/shared/AppScrollableContainer.svelte";
	import ChangedFilesContextMenu from "$components/shared/ChangedFilesContextMenu.svelte";
	import ReduxResult from "$components/shared/ReduxResult.svelte";
	import EditModeFileListItem from "$components/workspace/EditModeFileListItem.svelte";
	import { getEditorUri, URL_SERVICE } from "$lib/backend/url";
	import { splitMessage } from "$lib/commits/commitMessage";
	import { hasUnresolvedConflictsOnDisk } from "$lib/files/conflictCheck";
	import { conflictEntryHint, getConflictState } from "$lib/files/conflictEntryPresence";
	import { FILE_SERVICE } from "$lib/files/fileService";
	import { computeChangeStatus } from "$lib/files/fileStatus";
	import { MODE_SERVICE } from "$lib/mode/modeService";
	import { vscodePath } from "$lib/project/project";
	import { PROJECTS_SERVICE } from "$lib/project/projectsService";
	import { createCommitSelection } from "$lib/selection/key";
	import { STACK_SERVICE } from "$lib/stacks/stackService.svelte";
	import { UI_STATE } from "$lib/state/uiState.svelte";
	import { useUserAvatarUrl } from "$lib/user/userAvatar.svelte";
	import { inject } from "@gitbutler/core/context";

	import { AsyncButton, Avatar, Badge, Button, InfoButton, Modal, TestId } from "@gitbutler/ui";
	import { SvelteMap, SvelteSet } from "svelte/reactivity";
	import type { ConflictState } from "$lib/files/conflictEntryPresence";
	import type { EditModeMetadata, TreeChange } from "@gitbutler/but-sdk";
	import type { ConflictEntryPresence } from "@gitbutler/but-sdk";
	import type { FileStatus } from "@gitbutler/ui/components/file/types";

	type Props = {
		projectId: string;
		editModeMetadata: EditModeMetadata;
	};

	const { projectId, editModeMetadata }: Props = $props();

	const projectService = inject(PROJECTS_SERVICE);
	const projectQuery = $derived(projectService.getProject(projectId));

	const stackService = inject(STACK_SERVICE);
	const modeService = inject(MODE_SERVICE);
	const uiState = inject(UI_STATE);
	const urlService = inject(URL_SERVICE);
	const fileService = inject(FILE_SERVICE);

	const userAvatarUrl = useUserAvatarUrl();

	const initialFiles = $derived(modeService.initialEditModeState({ projectId }));
	const uncommittedFiles = $derived(modeService.changesSinceInitialEditState({ projectId }));

	const [saveEdit, savingEdit] = modeService.saveEditAndReturnToWorkspaceMutation;
	const [abortEdit, abortingEdit] = modeService.abortEditAndReturnToWorkspaceMutation;

	let commitQuery = $derived(stackService.commitDetails(projectId, editModeMetadata.commitOid));

	let filesList = $state<HTMLDivElement | undefined>(undefined);
	let contextMenu = $state<ReturnType<typeof ChangedFilesContextMenu> | undefined>(undefined);
	let confirmSaveModal = $state<ReturnType<typeof Modal> | undefined>(undefined);

	interface FileEntry {
		path: string;
		status?: FileStatus;
		conflicted: boolean;
		conflictHint?: string;
		conflictEntryPresence?: ConflictEntryPresence;
	}

	const files = $derived.by(() => {
		if (!initialFiles.response || !uncommittedFiles.response) return [];

		const outputMap = new Map<string, FileEntry>();

		initialFiles.response.forEach(([initialFile, conflictEntryPresence]) => {
			outputMap.set(initialFile.path, {
				path: initialFile.path,
				conflicted: !!conflictEntryPresence,
				conflictHint: conflictEntryPresence ? conflictEntryHint(conflictEntryPresence) : undefined,
				conflictEntryPresence: conflictEntryPresence ?? undefined,
			});
		});

		uncommittedFiles.response.forEach((uncommitedFile) => {
			const outputFile = outputMap.get(uncommitedFile.path)!;
			if (outputFile) {
				// We don't want to set a status if the file is
				// conflicted because it will _always_ show up as
				// modified
				if (!outputFile.conflicted) {
					outputFile.status = computeChangeStatus(uncommitedFile);
				}
				return;
			}

			outputMap.set(uncommitedFile.path, {
				path: uncommitedFile.path,
				conflicted: false,
				status: computeChangeStatus(uncommitedFile),
			});
		});

		const orderedOutput = Array.from(outputMap.values());
		orderedOutput.sort((a, b) => {
			// Float conflicted files to the top
			if (a.conflicted && !b.conflicted) {
				return -1;
			} else if (!a.conflicted && b.conflicted) {
				return 1;
			}

			return a.path.localeCompare(b.path);
		});

		return orderedOutput;
	});

	// Create a mapping from file paths to TreeChange objects for context menu
	const filePathToTreeChange = $derived(
		new Map<string, TreeChange>([
			...(initialFiles.response?.map(([f]) => [f.path, f] as [string, TreeChange]) || []),
			...(uncommittedFiles.response?.map((f) => [f.path, f] as [string, TreeChange]) || []),
		]),
	);

	function getTreeChangeForFile(file: FileEntry): TreeChange | undefined {
		return filePathToTreeChange.get(file.path);
	}

	const conflictedFiles = $derived(files.filter((file) => file.conflicted));

	let manuallyResolvedFiles = new SvelteSet<string>();

	// Per-file conflict state, updated by re-reading file content from disk.
	// Re-reads when uncommittedFiles changes (driven by the file watcher).
	const conflictStates = new SvelteMap<string, ConflictState>();

	$effect(() => {
		// Subscribe to uncommittedFiles so we re-read when files change on disk.
		void uncommittedFiles.response;

		for (const file of files) {
			if (!file.conflictEntryPresence) continue;
			const presence = file.conflictEntryPresence;
			const path = file.path;
			fileService.readFromWorkspace(path, projectId).then((result) => {
				conflictStates.set(path, getConflictState(presence, result.data.content));
			});
		}
	});

	async function abort(force: boolean) {
		if (loading) return;
		await abortEdit({ projectId, force });
		// Force-refresh the mode cache so the edit route's $effect sees
		// the updated mode immediately and navigates to workspace.
		// Without this, the cache relies on async tag invalidation which
		// can be delayed, leaving us stuck on the edit page.
		await modeService.fetchMode(projectId);
	}

	async function save() {
		if (loading) return;
		await saveEdit({ projectId });
		await modeService.fetchMode(projectId);
	}

	async function handleSave() {
		if (await hasUnresolvedConflictsOnDisk(files, manuallyResolvedFiles, fileService, projectId)) {
			confirmSaveModal?.show();
			return;
		}

		await save();
	}

	async function openAllConflictedFiles(projectPath: string) {
		for (const file of conflictedFiles) {
			const path = getEditorUri({
				schemeId: uiState.global.defaultCodeEditor.current.schemeIdentifer,
				path: [vscodePath(projectPath), file.path],
			});
			urlService.openExternalUrl(path);
		}
	}

	let isCommitListScrolled = $state(false);

	const loading = $derived(savingEdit.current.isLoading || abortingEdit.current.isLoading);

	let abortModal = $state<Modal>();
</script>

<Modal
	bind:this={abortModal}
	type="warning"
	width={420}
	title={t('workspace.editCommit.abortModalTitle')}
>
	<p>
		{t('workspace.editCommit.abortModalDesc1')}
	</p>
	<br />
	<p class="clr-text-2">
		{t('workspace.editCommit.abortModalDesc2')}
	</p>
	{#snippet controls(close)}
		<Button kind="outline" onclick={close}>{t('common.cancel')}</Button>
		<AsyncButton
			style="danger"
			action={async () => {
				await abort(true);
				close();
			}}>{t('workspace.editCommit.abortEditMode')}</AsyncButton
		>
	{/snippet}
</Modal>

<div class="editmode-wrapper" data-testid={TestId.EditMode}>
	<ReduxResult {projectId} result={projectQuery.result}>
		{#snippet children(project)}
			<div class="editmode__container">
				<h2 class="editmode__title text-18 text-body text-bold">
					{t('workspace.editCommit.editing')} <span class="code-string">
						{editModeMetadata.commitOid.slice(0, 7)}
					</span>
					<InfoButton title={t('workspace.editCommit.editModeTitle')}>
						{t('workspace.editCommit.editModeDesc')}
					</InfoButton>
				</h2>

				<div class="commit-group">
					<div class="card commit-card">
						<ReduxResult {projectId} result={commitQuery.result}>
							{#snippet children(commit)}
								{@const authorImgUrl = commit
									? (userAvatarUrl(commit.author.email) ?? commit.author.gravatarUrl)
									: undefined}
								{@const title = splitMessage(commit.message).title}
								<h3 class="text-13 text-semibold text-body commit-card__title">
									{title || t('workspace.editCommit.undefined')}
								</h3>

								{#if commit}
									<div class="text-11 commit-card__details">
										{#if authorImgUrl && commit.author.email}
											<Avatar
												srcUrl={authorImgUrl}
												username={commit.author.name || commit.author.email}
												tooltip={commit.author.email}
											/>
											<span class="commit-card__divider">•</span>
										{/if}
										<span class="">{editModeMetadata.commitOid.slice(0, 7)}</span>
										<span class="commit-card__divider">•</span>
										<span class="">{commit.author.name}</span>
									</div>
								{/if}

								<div class="commit-card__type-indicator"></div>
							{/snippet}
						</ReduxResult>
					</div>

					<div bind:this={filesList} class="card files">
						<div class="header" class:show-border={isCommitListScrolled}>
							<h3 class="text-15 text-semibold">{t('workspace.editCommit.commitFiles')}</h3>
							<Badge>{files.length}</Badge>
						</div>
						<ScrollableContainer
							onscrollTop={(visible) => {
								isCommitListScrolled = !visible;
							}}
						>
							{#each files as file (file.path)}
								<EditModeFileListItem
									filePath={file.path}
									pathFirst={uiState.global.pathFirst.current}
									fileStatus={file.status}
									conflictHint={file.conflictHint}
									conflictEntryPresence={file.conflictEntryPresence}
									conflictState={conflictStates.get(file.path) ?? "unknown"}
									manuallyResolved={manuallyResolvedFiles.has(file.path)}
									onresolveclick={file.conflicted
										? () => manuallyResolvedFiles.add(file.path)
										: undefined}
									oncontextmenu={(e) => {
										const treeChange = getTreeChangeForFile(file);
										if (treeChange) {
											contextMenu?.open(e, { changes: [treeChange] });
										}
									}}
								/>
							{/each}
						</ScrollableContainer>
					</div>
				</div>

				<p class="text-12 text-body editmode__helptext">
					{t('workspace.editCommit.helptext')}
					<br />
					{t('workspace.editCommit.helptextExit')}
				</p>

				<div class="editmode__actions">
					<div class="flex flex-1">
						{#if conflictedFiles.length > 0}
							<Button
								kind="outline"
								icon="open-in-ide"
								reversedDirection
								onclick={() => openAllConflictedFiles(project.path)}
								tooltip={conflictedFiles.length === 1
									? t('workspace.editCommit.openConflictedSingle')
									: t('workspace.editCommit.openConflictedMultiple')}
							>
								{t('workspace.editCommit.openConflicted')}
							</Button>
						{/if}
					</div>
					<ReduxResult result={uncommittedFiles.result} {projectId}>
						{#snippet children(uncommittedFiles, { projectId: _projectId })}
							{#if uncommittedFiles.length === 0}
									<Button kind="outline" onclick={() => abort(false)} disabled={loading} {loading}
										>{t('workspace.editCommit.abort')}</Button
									>
								{:else}
									<Button
										kind="outline"
										onclick={() => abortModal?.show()}
										disabled={loading}
										{loading}>{t('workspace.editCommit.abort')}</Button
									>
								{/if}
						{/snippet}
					</ReduxResult>
					<Button
						testId={TestId.EditModeSaveAndExitButton}
						style="pop"
						icon="tick"
						onclick={handleSave}
						disabled={loading}
						{loading}
					>
						{t('workspace.editCommit.saveAndExit')}
					</Button>
				</div>
			</div>

			<ChangedFilesContextMenu
				bind:this={contextMenu}
				{projectId}
				trigger={filesList}
				stackId={undefined}
				selectionId={createCommitSelection({ commitId: editModeMetadata.commitOid })}
				editMode={true}
			/>
		{/snippet}
	</ReduxResult>
</div>

<Modal
	bind:this={confirmSaveModal}
	title={t('workspace.editCommit.saveAndExitTitle')}
	type="warning"
	width="small"
	onSubmit={async (close) => {
		await save();
		close();
	}}
>
	<p class="text-13 text-body helper-text">
		{t('workspace.editCommit.saveAndExitDesc')}
	</p>
	{#snippet controls(close)}
		<Button kind="outline" type="reset" onclick={close}>{t('common.cancel')}</Button>
		<Button style="danger" type="submit" {loading}>{t('workspace.editCommit.saveAndExitTitle')}</Button>
	{/snippet}
</Modal>

